/**
 * @fileoverview Shared outside-click handler for dropdown/popover components.
 *
 * Provides a configurable outside-click listener that can optionally also
 * close on scroll, resize, and Escape key press.  Returns an AbortController
 * for lifecycle-safe cleanup.
 *
 * Two usage modes:
 *   1. **Cycle mode** — call `attachOutsideClick()`, store the returned AC,
 *      call `ac.abort()` on close.  Re-call on next open.
 *      Used by: Combobox, ClipBox, DynamicSearch.
 *
 *   2. **Signal mode** — pass an existing `signal` into `bindOutsideClick()`.
 *      The listener is torn down when the parent AC is aborted.
 *      Used by: ColorPicker.
 *
 * @module shared/outsideClick
 */

// ── Cycle mode ─────────────────────────────────────────────

/**
 * Attach document-level listeners that detect clicks outside a container
 * and its floating element, then invoke `onClose`.
 *
 * Returns an `AbortController` — call `.abort()` to remove all listeners.
 *
 * @param {HTMLElement}  containerEl — the component root element
 * @param {HTMLElement}  floatingEl  — the floating dropdown / popover element
 * @param {Function}     onClose     — callback invoked when an outside interaction is detected
 * @param {Object}       [options]
 * @param {boolean}      [options.scroll=false]   — also close on scroll outside the floating
 * @param {boolean}      [options.resize=false]   — also close on window resize
 * @param {boolean}      [options.escape=false]   — also close on Escape key
 * @param {number}       [options.guardMs=0]      — ignore events within this ms of attachment
 *                                                  (prevents race conditions with the opening click)
 * @returns {AbortController}
 */
export function attachOutsideClick(containerEl, floatingEl, onClose, options = {}) {
    const {
        scroll  = false,
        resize  = false,
        escape  = false,
        guardMs = 0,
    } = options;

    const ac = new AbortController();
    const signal = ac.signal;
    const attachedAt = guardMs > 0 ? performance.now() : 0;

    const guarded = (fn) => {
        if (guardMs <= 0) return fn;
        return (...args) => {
            if (performance.now() - attachedAt < guardMs) return;
            fn(...args);
        };
    };

    // Mousedown outside container + floating → close
    document.addEventListener('mousedown', guarded((e) => {
        if (containerEl.contains(e.target) || floatingEl.contains(e.target)) return;
        onClose();
    }), { signal });

    // Optional: scroll outside the floating → close
    if (scroll) {
        document.addEventListener('scroll', guarded((e) => {
            if (floatingEl.contains(e.target)) return;
            onClose();
        }), { signal, capture: true });
    }

    // Optional: window resize → close
    if (resize) {
        window.addEventListener('resize', guarded(() => {
            onClose();
        }), { signal });
    }

    // Optional: Escape key → close
    if (escape) {
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') onClose();
        }, { signal });
    }

    return ac;
}

// ── Signal mode ────────────────────────────────────────────

/**
 * Bind an outside-click listener using a parent AbortController signal.
 *
 * Unlike `attachOutsideClick`, this does NOT create its own AC.
 * The listener lives until the given `signal` is aborted.
 * Use an `isActive` guard when the listener must ignore clicks
 * while the component is in a closed/inactive state.
 *
 * @param {HTMLElement}  containerEl — the component root element
 * @param {Function}     onClose     — callback invoked on outside click
 * @param {Function}     [isActive]  — returns true when outside clicks should be processed
 * @param {AbortSignal}  signal      — parent AbortController signal for cleanup
 */
export function bindOutsideClick(containerEl, onClose, isActive, signal) {
    document.addEventListener('mousedown', (e) => {
        if (isActive && !isActive()) return;
        if (containerEl.contains(e.target)) return;
        onClose();
    }, signal ? { signal } : undefined);
}
